```class Solution {
public:
    string baseNeg2(int n) {
        if (n == 0) return "0";
        string res = "";
        while (n != 0) {
            int r = n % (-2);
            n /= -2;
            if (r < 0) {
                n++;
                r += 2;
            }
            res = to_string(r) + res;
        }
        return res;
    }
};
